def all_downsets(n):
    # recursively generate downsets as ideals of Boolean lattice? For n<=5
    subs=list(range(1<<n))
    # brute all families for n=4 impossible 2^16 ok
    for mask in range(1<<(1<<n)):
        D=[s for i,s in enumerate(subs) if (mask>>i)&1]
        ok=True
